let sessionConfig: SessionConfig

function _useSession(event: UseSessionEvent, config: Partial<SessionConfig> = {}) {
  if (!sessionConfig) {
    const runtimeConfig = useRuntimeConfig(isEvent(event) ? event : undefined)
    const envSessionPassword = `${runtimeConfig.nitro?.envPrefix || 'NUXT_'}SESSION_PASSWORD`

    sessionConfig = defu({ password: process.env[envSessionPassword] }, runtimeConfig.session)
    if (!sessionConfig.password) {
      console.error(`[nuxt-auth-utils] ${envSessionPassword} environment variable or runtimeConfig.session.password was not set.`)
    }
  }
  const finalConfig = defu(config, sessionConfig) as SessionConfig
  return useSession<UserSession>(event, finalConfig)
}

export const cache: RouteRuleCtor<"cache"> = ((m) =>
  function cacheRouteRule(event, next) {
    if (!event.context.matchedRoute) {
      return next();
    }
    const cachedHandlers: Map<string, EventHandler> = ((globalThis as any).__nitroCachedHandlers ??=
      new Map());
    const { handler, route } = event.context.matchedRoute;
    const key = `${m.route}:${route}`;
    let cachedHandler = cachedHandlers.get(key);
    if (!cachedHandler) {
      cachedHandler = defineCachedHandler(handler, {
        group: "nitro/route-rules",
        name: key,
        ...m.options,
      });
      cachedHandlers.set(key, cachedHandler);
    }
    return cachedHandler(event);
  }) satisfies RouteRuleCtor<"cache">;

export async function scanHandlers(nitro: Nitro) {
  const middleware = await scanMiddleware(nitro);

  const handlers = await Promise.all([
    scanServerRoutes(nitro, nitro.options.apiDir || "api", nitro.options.apiBaseURL || "/api"),
    scanServerRoutes(nitro, nitro.options.routesDir || "routes"),
  ]).then((r) => r.flat());

  const seenHandlers = new Set<string>();
  nitro.scannedHandlers = [
    ...middleware,
    ...handlers.filter((h) => {
      const key = `${h.route}\0${h.method}\0${h.env}`;
      return seenHandlers.has(key) ? false : (seenHandlers.add(key), true);
    }),
  ];

  nitro.routing.sync();

  return handlers;
}

import type { H3Event } from 'h3'
