export const useImage = (event?: H3Event): $Img => {
  const config = useRuntimeConfig()
  const nuxtApp = useNuxtApp()

  return nuxtApp.$img as $Img || nuxtApp._img || (nuxtApp._img = createImage({
    ...imageOptions,
    event: event || nuxtApp.ssrContext?.event,
    nuxt: {
      baseURL: config.app.baseURL,
    },
    runtimeConfig: config,
  }))
}

export function clearNuxtState (
  keys?: string | string[] | ((key: string) => boolean),
  opts?: ClearNuxtStateOptions,
): void {
  const reset = opts?.reset ?? useStateDefaults.resetOnClear

  const nuxtApp = useNuxtApp()
  const _allKeys = Object.keys(nuxtApp.payload.state)
    .filter(key => key.startsWith(useStateKeyPrefix))
    .map(key => key.substring(useStateKeyPrefix.length))

  const _keys: string[] = !keys
    ? _allKeys
    : typeof keys === 'function'
      ? _allKeys.filter(keys)
      : toArray(keys)

  for (const _key of _keys) {
    const key = useStateKeyPrefix + _key
    if (key in nuxtApp.payload.state) {
      if (reset && nuxtApp._state[key]) {
        nuxtApp.payload.state[key] = nuxtApp._state[key]._default()
      } else {
        delete nuxtApp.payload.state[key]
      }
    }
  }
}

const create = <T extends Component>(component: T, _options?: OverlayOptions<ComponentProps<T>>): OverlayInstance<T> => {
  const { props, defaultOpen, destroyOnClose } = _options || {}

  const options = reactive<Overlay>({
    id: Symbol(import.meta.dev ? 'useOverlay' : ''),
    isOpen: !!defaultOpen,
    component: markRaw(component!),
    isMounted: !!defaultOpen,
    destroyOnClose: !!destroyOnClose,
    originalProps: props || {},
    props: { ...props }
  })

  overlays.push(options)

  return {
    ...options,
    open: <T extends Component>(props?: ComponentProps<T>) => open(options.id, props),
    close: value => close(options.id, value),
    patch: <T extends Component>(props: Partial<ComponentProps<T>>) => patch(options.id, props)
  }
}

