export const useDetectors = (event: H3Event | undefined, config: { cookieKey: string }, nuxtApp?: NuxtApp) => {
  if (import.meta.server && !event) {
    throw new Error('H3Event is required for server-side locale detection')
  }

  const runtimeI18n = useRuntimeI18n(nuxtApp)

  return {
    cookie: () => getCookieLocale(event, config.cookieKey),
    header: () => (import.meta.server ? getHeaderLocale(event) : undefined),
    navigator: () => (import.meta.client ? getNavigatorLocale(event) : undefined),
    host: (path: string) => getHostLocale(event, path, runtimeI18n.domainLocales),
    route: (path: string | CompatRoute) => getRouteLocale(event, path),
  }
}

export function isExistingNuxtRoute(path: string) {
  if (path === '') { return }
  // TODO: path should not have base url - check if base url is stripped earlier
  // skip nuxt error route - this path is hardcoded within nitro context code in nuxt
  if (path.endsWith('/__nuxt_error')) { return }

  // skip disabled i18n routes - this prevent a redirect if there is a catch all route
  const disabledI18nResolvedMatch = disabledI18nMatcher.resolve({ path }, { path: '/', name: '', matched: [], params: {}, meta: {} })
  if (disabledI18nResolvedMatch.matched.length > 0) {
    return
  }

  const resolvedMatch = matcher.resolve({ path }, { path: '/', name: '', matched: [], params: {}, meta: {} })

  return resolvedMatch.matched.length > 0 ? resolvedMatch : undefined
}

export function createLocaleRouteNameGetter(
  defaultLocale: string,
): (name: RouteRecordNameGeneric | null, locale: string) => string {
  // no route localization
  if (!__I18N_ROUTING__ && !__DIFFERENT_DOMAINS__) {
    return routeName => normalizeRouteName(routeName)
  }

  // default locale routes have default suffix
  if (__I18N_STRATEGY__ === 'prefix_and_default') {
    return (name, locale) => getLocalizedRouteName(normalizeRouteName(name), locale, locale === defaultLocale)
  }

  // routes are localized
  return (name, locale) => getLocalizedRouteName(normalizeRouteName(name), locale, false)
}

export function _useLocaleHead(ctx: ComposableContext, options: Required<I18nHeadOptions>): Ref<I18nHeadMetaInfo> {
  const metaObject = ref(_localeHead(createHeadContext(ctx, options)))

  if (import.meta.client) {
    const unsub = watch([() => ctx.router.currentRoute.value, () => ctx.getLocale()], () => {
      metaObject.value = _localeHead(createHeadContext(ctx, options))
      __I18N_STRICT_SEO__ && ctx.head?.patch(metaObject.value)
    })
    if (getCurrentScope()) {
      onScopeDispose(unsub)
    }
  }

  __I18N_STRICT_SEO__ && ctx.head?.patch(metaObject.value)

  return metaObject
}

export function _useShortcuts() {
  const macOS = computed(() => import.meta.client && navigator && navigator.userAgent && navigator.userAgent.match(/Macintosh;/))

  const metaSymbol = ref(' ')

  const activeElement = useActiveElement()
  const usingInput = computed(() => {
    const tagName = activeElement.value?.tagName
    const contentEditable = activeElement.value?.contentEditable

    const usingInput = (tagName === 'INPUT' || tagName === 'TEXTAREA' || contentEditable === 'true' || contentEditable === 'plaintext-only')

    if (usingInput) {
      return ((activeElement.value as any)?.name as string) || true
    }

    return false
  })

  onMounted(() => {
    metaSymbol.value = macOS.value ? '⌘' : 'Ctrl'
  })

  return {
    macOS,
    metaSymbol,
    activeElement,
    usingInput,
  }
}

export default defineProvider<TwicpicsOptions>({
  getImage: (src, { modifiers, baseURL = '/' }) => {
    const { width, height, fit, ...providerModifiers } = modifiers

    let w = width
    let h = height

    if (width || height) {
      if (fit && fit === 'outside') {
      // fit = outside is equivalent to twicPics contain ( max( width, height ) x max( width, height ) )
        w = Math.max(width || 0, height || 0)
        h = Math.max(width || 0, height || 0)
      }
      providerModifiers[fits(fit as keyof typeof fits)] = `${w || '-'}x${h || '-'}`
    }

    const operations = operationsGenerator(providerModifiers)

    return {
      url: joinURL(baseURL, src + (operations ? ('?twic=v1/' + operations) : '')),
    }
  },
})

export function startScheduleRunner({
  waitUntil,
}: {
  waitUntil?: ((promise: Promise<unknown>) => void) | undefined;
} = {}): void {
  if (!scheduledTasks || scheduledTasks.length === 0 || process.env.TEST) {
    return;
  }

  const payload: TaskPayload = {
    scheduledTime: Date.now(),
  };

  for (const schedule of scheduledTasks) {
    new Cron(schedule.cron, async () => {
      await Promise.all(
        schedule.tasks.map((name) =>
          runTask(name, {
            payload,
            context: { waitUntil },
          }).catch((error) => {
            console.error(`Error while running scheduled task "${name}"`, error);
          })
        )
      );
    });
  }
}

