// Conditional types, either one or other
type Without<T, U> = { [P in Exclude<keyof T, keyof U>]?: never }
type XOR<T, U> = (T | U) extends object ? (Without<T, U> & U) | (Without<U, T> & T) : T | U

export type OpenWindowFeatures = {
  popup?: boolean
  noopener?: boolean
  noreferrer?: boolean
} & XOR<{ width?: number }, { innerWidth?: number }>
  & XOR<{ height?: number }, { innerHeight?: number }>
  & XOR<{ left?: number }, { screenX?: number }>
  & XOR<{ top?: number }, { screenY?: number }>

function resolveIngestUrl(config: AxiomConfig): string {
  const encodedDataset = encodeURIComponent(config.dataset)

  if (!config.edgeUrl) {
    const baseUrl = config.baseUrl ?? 'https://api.axiom.co'
    return `${baseUrl}/v1/datasets/${encodedDataset}/ingest`
  }

  try {
    const parsed = new URL(config.edgeUrl)
    if (parsed.pathname === '' || parsed.pathname === '/') {
      parsed.pathname = `/v1/ingest/${encodedDataset}`
      return parsed.toString()
    }
    parsed.pathname = parsed.pathname.replace(/\/+$/, '')
    return parsed.toString()
  } catch {
    console.warn(`[evlog/axiom] edgeUrl "${config.edgeUrl}" is not a valid URL, falling back to string concatenation.`)
    const trimmed = config.edgeUrl.replace(/\/+$/, '')
    return `${trimmed}/v1/ingest/${encodedDataset}`
  }
}

export function toDatadogLog(event: WideEvent): Record<string, unknown> {
  const ms = Date.parse(event.timestamp)
  const tags = [`env:${event.environment}`]
  const versionTag = event.version
  if (versionTag !== undefined && versionTag !== null && versionTag !== '') {
    tags.push(`version:${String(versionTag)}`)
  }

  return {
    message: formatDatadogMessageLine(event),
    evlog: sanitizeWideEventForDatadog(event),
    service: event.service,
    status: resolveDatadogLogStatus(event),
    ddsource: 'evlog',
    ddtags: tags.join(','),
    ...(Number.isFinite(ms) ? { timestamp: ms } : {}),
  }
}

async function resolveFilePath(dir: string, maxSizePerFile?: number): Promise<string> {
  const date = getDateString()
  const basePath = join(dir, `${date}.jsonl`)

  if (!maxSizePerFile) return basePath

  try {
    const stats = await stat(basePath)
    if (stats.size < maxSizePerFile) return basePath
  } catch {
    return basePath
  }

  for (let i = 1; i < 1000; i++) {
    const rotatedPath = join(dir, `${date}.${i}.jsonl`)
    try {
      const stats = await stat(rotatedPath)
      if (stats.size < maxSizePerFile) return rotatedPath
    } catch {
      return rotatedPath
    }
  }

  return join(dir, `${date}.999.jsonl`)
}

function getHeadersFromEnv(): Record<string, string> | undefined {
  const headersEnv = process.env.OTEL_EXPORTER_OTLP_HEADERS || process.env.NUXT_OTLP_HEADERS
  if (headersEnv) {
    const headers: Record<string, string> = {}
    const decoded = decodeURIComponent(headersEnv)
    for (const pair of decoded.split(',')) {
      const eqIndex = pair.indexOf('=')
      if (eqIndex > 0) {
        const key = pair.slice(0, eqIndex).trim()
        const value = pair.slice(eqIndex + 1).trim()
        if (key && value) {
          headers[key] = value
        }
      }
    }
    if (Object.keys(headers).length > 0) return headers
  }

  const auth = process.env.NUXT_OTLP_AUTH
  if (auth) {
    return { Authorization: auth }
  }

  return undefined
}

function buildOTLPPayload(events: WideEvent[], config: OTLPConfig): ExportLogsServiceRequest {
  const grouped = new Map<string, WideEvent[]>()
  for (const event of events) {
    const key = `${event.service}::${event.environment}`
    const group = grouped.get(key)
    if (group) group.push(event)
    else grouped.set(key, [event])
  }
  return {
    resourceLogs: Array.from(grouped.values()).map(groupEvents => ({
      resource: { attributes: buildResourceAttributes(groupEvents[0]!, config) },
      scopeLogs: [
        {
          scope: { name: 'evlog', version: '1.0.0' },
          logRecords: groupEvents.map(toOTLPLogRecord),
        },
      ],
    })),
  }
}

export function createSentryDrain(overrides?: Partial<SentryConfig>) {
  return defineHttpDrain<SentryConfig>({
    name: 'sentry',
    resolve: async () => {
      const config = await resolveAdapterConfig<SentryConfig>('sentry', SENTRY_FIELDS, overrides)
      if (!config.dsn) {
        console.error('[evlog/sentry] Missing DSN. Set NUXT_SENTRY_DSN/SENTRY_DSN env var or pass to createSentryDrain()')
        return null
      }
      return config as SentryConfig
    },
    encode: (events, config) => {
      const { url, authHeader } = getSentryEnvelopeUrl(config.dsn)
      const logs = events.map(event => toSentryLog(event, config))
      return {
        url,
        headers: {
          'Content-Type': 'application/x-sentry-envelope',
          'X-Sentry-Auth': authHeader,
        },
        body: buildEnvelopeBody(logs, config.dsn),
      }
    },
  })
}

function getSizesVariant(key: string, size: string, height: number | undefined, hwRatio: number, ctx: ImageCTX): ImageSizesVariant | undefined {
  const screenMaxWidth = (ctx.options.screens && ctx.options.screens[key]) || Number.parseInt(key)
  const isFluid = size.endsWith('vw')
  if (!isFluid && /^\d+$/.test(size)) {
    size = size + 'px'
  }
  if (!isFluid && !size.endsWith('px')) {
    return undefined
  }
  let _cWidth = Number.parseInt(size)
  if (!screenMaxWidth || !_cWidth) {
    return undefined
  }
  if (isFluid) {
    _cWidth = Math.round((_cWidth / 100) * screenMaxWidth)
  }
  const _cHeight = hwRatio ? Math.round(_cWidth * hwRatio) : height
  return {
    size,
    screenMaxWidth,
    _cWidth,
    _cHeight,
  }
}

function setLinks() {
  if (route.fullPath === '/') {
    return [{ title: 'Home', href: '/' }]
  }

  const segments = route.fullPath.split('/').filter(item => item !== '')

  const breadcrumbs = segments.map((item, index) => {
    const str = item.replace(/-/g, ' ')
    const title = str
      .split(' ')
      .map(word => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase())
      .join(' ')

    return {
      title,
      href: `/${segments.slice(0, index + 1).join('/')}`,
    }
  })

  return [{ title: 'Home', href: '/' }, ...breadcrumbs]
}

function buildEvents(): TimedEvent[] {
  const events: TimedEvent[] = []

  steps.forEach((step, i) => {
    const at = STEP_BASE + i * STEP_INTERVAL

    events.push({
      at,
      run: () => {
        phase.value = i
        if (step.id === 'first') {
          inputTokens.value = FINAL_INPUT
        }
        if (step.id === 'stream-1') {
          outputTokens.value = Math.round(FINAL_OUTPUT * 0.4)
        }
        if (step.id === 'tool-call') {
          toolName.value = 'getWeather'
        }
        if (step.id === 'stream-2') {
          outputTokens.value = FINAL_OUTPUT
        }
        if (step.id === 'finish') {
          finished.value = true
        }
      },
    })
  })

  return events
}

async function scanDir(nitro: Nitro, dir: string, name: string): Promise<FileInfo[]> {
  const fileNames = await glob(join(name, GLOB_SCAN_PATTERN), {
    cwd: dir,
    dot: true,
    ignore: nitro.options.ignore,
    absolute: true,
  }).catch((error) => {
    if (error?.code === "ENOTDIR") {
      nitro.logger.warn(`Ignoring \`${join(dir, name)}\`. It must be a directory.`);
      return [];
    }
    throw error;
  });
  return fileNames
    .map((fullPath) => {
      return {
        fullPath,
        path: relative(join(dir, name), fullPath),
      };
    })
    .sort((a, b) => a.path.localeCompare(b.path));
}

export function getCollectionFieldsTypes(schema: Draft07) {
  const sortedKeys = getOrderedSchemaKeys(schema)
  return sortedKeys.reduce((acc, key) => {
    const property = describeProperty(schema, key)
    if (property.json) {
      acc[key] = 'json'
    }
    else if (property.sqlType === 'BOOLEAN') {
      acc[key] = 'boolean'
    }
    else if (property.sqlType === 'DATE') {
      acc[key] = 'date'
    }
    else if (property.sqlType === 'INT') {
      acc[key] = 'number'
    }
    else {
      acc[key] = 'string'
    }
    return acc
  }, {} as Record<string, 'string' | 'number' | 'boolean' | 'date' | 'json'>)
}

function buildEvents(): TimedEvent[] {
  const events: TimedEvent[] = []

  requests.forEach((_, i) => {
    const base = i * ROW_INTERVAL
    events.push({
      at: base + PHASE_INCOMING_AT,
      run: () => {
        rowPhase.value = rowPhase.value.map((p, idx) => idx === i ? 'incoming' : p)
      },
    })
    events.push({
      at: base + PHASE_INCOMING_AT + PHASE_EVALUATED_AT,
      run: () => {
        rowPhase.value = rowPhase.value.map((p, idx) => idx === i ? 'evaluated' : p)
      },
    })
    events.push({
      at: base + PHASE_INCOMING_AT + PHASE_EVALUATED_AT + PHASE_RESOLVED_AT,
      run: () => {
        rowPhase.value = rowPhase.value.map((p, idx) => idx === i ? 'resolved' : p)
      },
    })
  })

  return events
}

function buildEvents(): TimedEvent[] {
  const events: TimedEvent[] = []

  events.push({ at: START_AT - 50, run: () => {
    phase.value = 'flowing'
  } })

  let maxAt = 0
  levels.forEach((_, rowIdx) => {
    for (let i = 1; i <= TOTAL_DOTS; i++) {
      const at = START_AT + rowIdx * ROW_STAGGER + i * DOT_INTERVAL
      maxAt = Math.max(maxAt, at)
      events.push({
        at,
        run: () => {
          const next = [...revealed.value]
          next[rowIdx] = i
          revealed.value = next
        },
      })
    }
  })

  events.push({ at: maxAt + 200, run: () => {
    phase.value = 'done'
  } })
  return events
}
